# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.shareintentdemo

import android.content.ActivityNotFoundException
import android.content.Intent
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.net.Uri
import android.util.Log
import android.widget.Toast

class ShareIntentActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_intent)

        val intent = getIntent()
        if (intent.action == Intent.ACTION_SEND) {
            handleShareIntent(intent)
        }
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val url = intent.getStringExtra(Intent.EXTRA_TEXT)
                processUrl(url)
            }
            "image/*" -> {
                try {
                    val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                    processImage(uri)
                } catch (e: Exception) {
                    Log.e("ShareIntentActivity", e.toString())
                }
            }
        }
    }

    private fun processUrl(url: String?) {
        if (url != null && !url.isEmpty()) {
            Toast.makeText(this, "Received URL: $url", Toast.LENGTH_SHORT).show()
            // You can perform any action you want with the received URL here
        } else {
            Toast.makeText(this, "No valid URL found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processImage(uri: Uri?) {
        if (uri != null) {
            try {
                val bitmap = MediaStore.Images.Media.getBitmap(contentResolver, uri)
                // You can perform any action you want with the received image here
                Toast.makeText(this, "Received Image", Toast.LENGTH_SHORT).show()
            } catch (e: Exception) {
                Log.e("ShareIntentActivity", e.toString())
            }
        } else {
            Toast.makeText(this, "No valid image found", Toast.LENGTH_SHORT).show()
        }
    }
}